const ShortsBeforeAfter = ({ item }) => {
  const frame = useCurrentFrame();
  const { fps, durationInFrames } = useVideoConfig();
  const p = item.props || {};
  const beforeLabel = p.beforeLabel || 'BEFORE';
  const afterLabel = p.afterLabel || 'AFTER';
  const beforeText = p.beforeText || '';
  const afterText = p.afterText || '';
  const beforeColor = p.beforeColor || '#f87171';
  const afterColor = p.afterColor || '#4ade80';
  const textColor = p.textColor || '#fafafa';
  const a = spring({ frame, fps, config: { damping: 15, stiffness: 100 } });
  const b = spring({ frame: frame - 10, fps, config: { damping: 15, stiffness: 100 } });
  const exit = interpolate(frame, [durationInFrames - 10, durationInFrames], [1, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const card = (label, text, color, enter, align) => (
    <div style={{
      width: 880, opacity: enter * exit,
      transform: `translateX(${(1 - enter) * (align === 'left' ? -40 : 40)}px)`,
      background: 'rgba(15,23,42,0.88)',
      borderRadius: 24,
      padding: '28px 32px',
      borderLeft: `8px solid ${color}`,
      marginBottom: 24,
    }}>
      <div style={{ fontSize: 24, fontWeight: 900, color, letterSpacing: 2, marginBottom: 10 }}>{label}</div>
      <div style={{ fontSize: 40, fontWeight: 800, color: textColor }}>{text}</div>
    </div>
  );
  return (
    <AbsoluteFill style={{ backgroundColor: 'transparent', justifyContent: 'center', alignItems: 'center' }}>
      <div>
        {card(beforeLabel, beforeText, beforeColor, a, 'left')}
        {card(afterLabel, afterText, afterColor, b, 'right')}
      </div>
    </AbsoluteFill>
  );
};

